('data-source-types', 'ph-da-foundations', 20, 'topic', NULL, NULL, NULL, 'Data Source Types', 'Compare transactional systems, event logs, surveys, spreadsheets, third-party data, and public datasets so the learner can choose appropriate analysis methods.', 'This expanded node deepens the Data Analyst roadmap with curated, role-relevant practice around Data Source Types.', 'side', 'ph-da-foundations', 99, 20, 3, 'beginner', 80, NULL, NULL, '{"generatedBy": "roadmap-platform", "version": "expanded-curated-expansion"}'::jsonb, true, true, '["Explain and apply Data Source Types in a data analyst workflow.", "Use Data Source Types to produce clearer, more reliable analysis evidence."]'::jsonb, '["Create notes, queries, workbook logic, dashboard checks, or analysis output demonstrating Data Source Types.", "Document assumptions, validation steps, and interpretation limits."]'::jsonb),
('analytical-deliverable-types', 'ph-da-foundations', 21, 'topic', NULL, NULL, NULL, 'Analytical Deliverable Types', 'Distinguish ad hoc analysis, recurring reports, dashboards, metric dictionaries, insight decks, and decision memos.', 'This expanded node deepens the Data Analyst roadmap with curated, role-relevant practice around Analytical Deliverable Types.', 'side', 'ph-da-foundations', 99, 21, 3, 'beginner', 80, NULL, NULL, '{"generatedBy": "roadmap-platform", "version": "expanded-curated-expansion"}'::jsonb, true, true, '["Explain and apply Analytical Deliverable Types in a data analyst workflow.", "Use Analytical Deliverable Types to produce clearer, more reliable analysis evidence."]'::jsonb, '["Create notes, queries, workbook logic, dashboard checks, or analysis output demonstrating Analytical Deliverable Types.", "Document assumptions, validation steps, and interpretation limits."]'::jsonb),
('stakeholder-interview-questions', 'ph-da-foundations', 22, 'topic', NULL, NULL, NULL, 'Stakeholder Interview Questions', 'Ask focused questions that uncover decision context, definitions, constraints, success criteria, and risk before doing analysis.', 'This expanded node deepens the Data Analyst roadmap with curated, role-relevant practice around Stakeholder Interview Questions.', 'side', 'ph-da-foundations', 99, 22, 3, 'beginner', 80, NULL, NULL, '{"generatedBy": "roadmap-platform", "version": "expanded-curated-expansion"}'::jsonb, true, true, '["Explain and apply Stakeholder Interview Questions in a data analyst workflow.", "Use Stakeholder Interview Questions to produce clearer, more reliable analysis evidence."]'::jsonb, '["Create notes, queries, workbook logic, dashboard checks, or analysis output demonstrating Stakeholder Interview Questions.", "Document assumptions, validation steps, and interpretation limits."]'::jsonb),
('spreadsheet-data-validation', 'ph-spreadsheets', 20, 'topic', NULL, NULL, NULL, 'Spreadsheet Data Validation Rules', 'Use validation lists, allowed ranges, input rules, and error prompts to reduce manual spreadsheet data quality issues.', 'This expanded node deepens the Data Analyst roadmap with curated, role-relevant practice around Spreadsheet Data Validation Rules.', 'side', 'ph-spreadsheets', 99, 20, 3, 'beginner', 80, NULL, NULL, '{"generatedBy": "roadmap-platform", "version": "expanded-curated-expansion"}'::jsonb, true, true, '["Explain and apply Spreadsheet Data Validation Rules in a data analyst workflow.", "Use Spreadsheet Data Validation Rules to produce clearer, more reliable analysis evidence."]'::jsonb, '["Create notes, queries, workbook logic, dashboard checks, or analysis output demonstrating Spreadsheet Data Validation Rules.", "Document assumptions, validation steps, and interpretation limits."]'::jsonb),
('conditional-formatting-analysis', 'ph-spreadsheets', 21, 'topic', NULL, NULL, NULL, 'Conditional Formatting for Analysis', 'Use conditional formatting to highlight outliers, thresholds, missing values, priority records, and exceptions without hiding raw data.', 'This expanded node deepens the Data Analyst roadmap with curated, role-relevant practice around Conditional Formatting for Analysis.', 'side', 'ph-spreadsheets', 99, 21, 3, 'beginner', 80, NULL, NULL, '{"generatedBy": "roadmap-platform", "version": "expanded-curated-expansion"}'::jsonb, true, true, '["Explain and apply Conditional Formatting for Analysis in a data analyst workflow.", "Use Conditional Formatting for Analysis to produce clearer, more reliable analysis evidence."]'::jsonb, '["Create notes, queries, workbook logic, dashboard checks, or analysis output demonstrating Conditional Formatting for Analysis.", "Document assumptions, validation steps, and interpretation limits."]'::jsonb),
('spreadsheet-lookup-patterns', 'ph-spreadsheets', 22, 'topic', NULL, NULL, NULL, 'Spreadsheet Lookup Patterns', 'Use XLOOKUP-style patterns to enrich records, audit mismatches, and avoid brittle manual copy-paste analysis.', 'This expanded node deepens the Data Analyst roadmap with curated, role-relevant practice around Spreadsheet Lookup Patterns.', 'side', 'ph-spreadsheets', 99, 22, 3, 'beginner', 80, NULL, NULL, '{"generatedBy": "roadmap-platform", "version": "expanded-curated-expansion"}'::jsonb, true, true, '["Explain and apply Spreadsheet Lookup Patterns in a data analyst workflow.", "Use Spreadsheet Lookup Patterns to produce clearer, more reliable analysis evidence."]'::jsonb, '["Create notes, queries, workbook logic, dashboard checks, or analysis output demonstrating Spreadsheet Lookup Patterns.", "Document assumptions, validation steps, and interpretation limits."]'::jsonb),
('sql-date-time-analysis', 'ph-sql-databases', 20, 'topic', NULL, NULL, NULL, 'SQL Date and Time Analysis', 'Use date extraction, intervals, truncation, rolling periods, and calendar logic for time-based business analysis.', 'This expanded node deepens the Data Analyst roadmap with curated, role-relevant practice around SQL Date and Time Analysis.', 'side', 'ph-sql-databases', 99, 20, 4, 'intermediate', 80, NULL, NULL, '{"generatedBy": "roadmap-platform", "version": "expanded-curated-expansion"}'::jsonb, true, true, '["Explain and apply SQL Date and Time Analysis in a data analyst workflow.", "Use SQL Date and Time Analysis to produce clearer, more reliable analysis evidence."]'::jsonb, '["Create notes, queries, workbook logic, dashboard checks, or analysis output demonstrating SQL Date and Time Analysis.", "Document assumptions, validation steps, and interpretation limits."]'::jsonb),
('cohort-retention-sql', 'ph-sql-databases', 21, 'topic', NULL, NULL, NULL, 'Cohort and Retention SQL', 'Build cohort tables and retention calculations using signup periods, activity windows, joins, and window functions.', 'This expanded node deepens the Data Analyst roadmap with curated, role-relevant practice around Cohort and Retention SQL.', 'side', 'ph-sql-databases', 99, 21, 5, 'intermediate', 80, NULL, NULL, '{"generatedBy": "roadmap-platform", "version": "expanded-curated-expansion"}'::jsonb, true, true, '["Explain and apply Cohort and Retention SQL in a data analyst workflow.", "Use Cohort and Retention SQL to produce clearer, more reliable analysis evidence."]'::jsonb, '["Create notes, queries, workbook logic, dashboard checks, or analysis output demonstrating Cohort and Retention SQL.", "Document assumptions, validation steps, and interpretation limits."]'::jsonb),
('analyst-dimensional-modeling', 'ph-sql-databases', 22, 'topic', NULL, NULL, NULL, 'Dimensional Modeling for Analysts', 'Understand facts, dimensions, grain, slowly changing attributes, and why BI-ready schemas reduce metric confusion.', 'This expanded node deepens the Data Analyst roadmap with curated, role-relevant practice around Dimensional Modeling for Analysts.', 'side', 'ph-sql-databases', 99, 22, 4, 'intermediate', 80, NULL, NULL, '{"generatedBy": "roadmap-platform", "version": "expanded-curated-expansion"}'::jsonb, true, true, '["Explain and apply Dimensional Modeling for Analysts in a data analyst workflow.", "Use Dimensional Modeling for Analysts to produce clearer, more reliable analysis evidence."]'::jsonb, '["Create notes, queries, workbook logic, dashboard checks, or analysis output demonstrating Dimensional Modeling for Analysts.", "Document assumptions, validation steps, and interpretation limits."]'::jsonb),
